export async function run(now = "2026-06-18T12:00:00.000Z") {
  await withDb(async (client) => {
    const nowDate = new Date(now);

    const acct = (await client.query("SELECT * FROM accounts LIMIT 1")).rows[0];
    const invoices = (await client.query("SELECT invoice_id, amount_cents, due_date, status FROM invoices")).rows;
    const shipments = (await client.query("SELECT shipment_id, sla_date, delivered_date, status FROM shipments")).rows;
    const regulatoryFlags = (await client.query("SELECT flag_id, type, status FROM regulatory_flags")).rows;
    const supportCases = (await client.query("SELECT case_id, severity, status FROM support_cases")).rows;
    const usageRow = (await client.query("SELECT prior_period_units, current_period_units FROM usage_periods LIMIT 1")).rows[0];

    const accountId = acct.account_id;
    const tier = acct.tier;

    const signals = [];

    if (regulatoryFlags.some(f => f.status === "open")) {
      signals.push("Regulatory hold");
    }
    if (invoices.some(i => i.status !== "paid" && Number(i.amount_cents) >= 2500000 && new Date(i.due_date) < nowDate)) {
      signals.push("Overdue invoice");
    }
    if (shipments.some(s => !s.delivered_date && new Date(s.sla_date) < nowDate)) {
      signals.push("Delayed shipment");
    }
    if (supportCases.some(s => s.status === "open" && (s.severity === "high" || s.severity === "critical"))) {
      signals.push("Escalated support");
    }
    if (usageRow && Number(usageRow.current_period_units) <= Number(usageRow.prior_period_units) * 0.7) {
      signals.push("Usage decline");
    }

    const qualifyingTiers = ["strategic", "enterprise"];
    const qualifies = qualifyingTiers.includes(tier) && signals.length > 0;

    const OWNER_MAP = {
      "Regulatory hold": "Legal",
      "Overdue invoice": "Finance",
      "Delayed shipment": "Customer Success",
      "Usage decline": "Customer Success",
      "Escalated support": "Support",
    };
    const OWNER_ORDER = ["Legal", "Finance", "Customer Success", "Support"];

    let owners = [];
    if (qualifies) {
      const ownerSet = new Set(signals.map(s => OWNER_MAP[s]));
      owners = OWNER_ORDER.filter(o => ownerSet.has(o));
    }

    const status = qualifies
      ? "At-risk escalation active with executive recovery owner routing and customer-visible audit history."
      : "Monitoring — no escalation required.";

    const riskSummary = `${signals.length} signals: ${signals.join(", ")}`;

    const nextStep = qualifies
      ? `${owners[0]} recovery review by 16:00`
      : "Continue standard monitoring.";

    const requestId = `req-workflow-${accountId}`;
    const dueAt = new Date(nowDate);
    dueAt.setUTCHours(16, 0, 0, 0);

    await client.query("DELETE FROM workflow_state");
    await client.query("DELETE FROM owner_tasks");
    await client.query("DELETE FROM customer_messages");
    await client.query("DELETE FROM audit_events");

    await client.query(
      "INSERT INTO workflow_state (request_id, account_id, title, status, next_step, risk_summary) VALUES ($1, $2, $3, $4, $5, $6)",
      [requestId, accountId, "Strategic Account Rescue", status, nextStep, riskSummary]
    );

    for (const owner of owners) {
      await client.query(
        "INSERT INTO owner_tasks (request_id, account_id, owner_group, title, due_at, status) VALUES ($1, $2, $3, $4, $5, $6)",
        [requestId, accountId, owner, `${owner} recovery action`, dueAt.toISOString(), "open"]
      );
    }

    const customerMsg = qualifies
      ? `Your account has been identified for priority attention due to active risk indicators. Our team has initiated a recovery workflow and assigned dedicated owners to address the concerns. We are committed to resolving these matters promptly and will be in touch to coordinate next steps and ensure your continued success.`
      : `Your account is under standard monitoring and no escalation is required at this time. Please contact us if you have any questions.`;

    await client.query(
      "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1, $2, $3)",
      [requestId, accountId, customerMsg]
    );

    const event = qualifies
      ? `Escalation workflow initiated. ${signals.length} risk signals detected. Recovery owners assigned: ${owners.join(", ")}.`
      : `Account monitoring check completed. No escalation required.`;

    await client.query(
      "INSERT INTO audit_events (request_id, account_id, event, occurred_at, customer_visible) VALUES ($1, $2, $3, $4, $5)",
      [requestId, accountId, event, nowDate.toISOString(), true]
    );
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

